const webhookData = $('Webhook Trigger').first().json;
const body = webhookData.body || webhookData;
const { projectId, runId } = body;

const ticketResponse = $('Query Tickets').first().json;
const correctionResponse = $('Query Corrections').first().json;

const tickets = Array.isArray(ticketResponse) ? ticketResponse : (ticketResponse.data || ticketResponse.tickets || []);
const corrections = Array.isArray(correctionResponse) ? correctionResponse : (correctionResponse.data || correctionResponse.corrections || []);

const totalTickets = tickets.length;
const completedTickets = tickets.filter(t => t.status === 'completed' || t.status === 'done').length;
const failedTickets = tickets.filter(t => t.status === 'failed' || t.status === 'rejected').length;

const cycleTimes = tickets
  .filter(t => t.completedAt && t.createdAt)
  .map(t => (new Date(t.completedAt) - new Date(t.createdAt)) / (1000 * 60 * 60));
const avgCycleTime = cycleTimes.length > 0
  ? cycleTimes.reduce((a, b) => a + b, 0) / cycleTimes.length
  : 0;

const correctionRate = totalTickets > 0 ? (corrections.length / totalTickets) * 100 : 0;
const defectRate = totalTickets > 0 ? (failedTickets / totalTickets) * 100 : 0;

return [{
  json: {
    projectId,
    runId,
    metrics: {
      totalTickets,
      completedTickets,
      failedTickets,
      throughput: completedTickets,
      avgCycleTimeHours: Math.round(avgCycleTime * 10) / 10,
      correctionRate: Math.round(correctionRate * 10) / 10,
      defectRate: Math.round(defectRate * 10) / 10,
      totalCorrections: corrections.length
    },
    tickets,
    corrections
  }
}];

const data = $json;
const { metrics, tickets, corrections } = data;

const patterns = [];
const bottlenecks = [];

if (metrics.correctionRate > 30) {
  patterns.push({ type: 'high-correction-rate', severity: 'warning', detail: metrics.correctionRate + '% of tickets required corrections' });
}
if (metrics.defectRate > 15) {
  patterns.push({ type: 'high-defect-rate', severity: 'critical', detail: metrics.defectRate + '% ticket failure rate' });
}
if (metrics.avgCycleTimeHours > 48) {
  patterns.push({ type: 'slow-cycle-time', severity: 'warning', detail: 'Average cycle time of ' + metrics.avgCycleTimeHours + 'h exceeds 48h target' });
}
if (metrics.throughput < metrics.totalTickets * 0.5) {
  patterns.push({ type: 'low-throughput', severity: 'warning', detail: 'Only ' + metrics.throughput + '/' + metrics.totalTickets + ' tickets completed' });
}

const correctionsByAgent = {};
(corrections || []).forEach(c => {
  const agent = c.assignedTo || c.agent || 'unknown';
  correctionsByAgent[agent] = (correctionsByAgent[agent] || 0) + 1;
});

const agentCorrections = Object.entries(correctionsByAgent)
  .sort(([,a], [,b]) => b - a);

if (agentCorrections.length > 0 && agentCorrections[0][1] > 3) {
  bottlenecks.push({
    type: 'agent-correction-hotspot',
    agent: agentCorrections[0][0],
    count: agentCorrections[0][1],
    suggestion: 'Consider skill refresh or workload redistribution'
  });
}

const phaseDistribution = {};
(tickets || []).forEach(t => {
  const phase = t.phase || t.ssdlcPhase || 'unknown';
  phaseDistribution[phase] = (phaseDistribution[phase] || 0) + 1;
});

const healthScore = Math.round(Math.max(0,
  100
  - (metrics.defectRate * 2)
  - (metrics.correctionRate * 0.5)
  - (Math.max(0, metrics.avgCycleTimeHours - 24) * 0.5)
));

return [{
  json: {
    ...data,
    analysis: {
      patterns,
      bottlenecks,
      correctionsByAgent: Object.fromEntries(agentCorrections),
      phaseDistribution,
      healthScore
    }
  }
}];

const data = $json;
const { metrics, analysis } = data;
const lessons = [];

if (analysis.patterns) {
  analysis.patterns.forEach(p => {
    if (p.type === 'high-correction-rate') {
      lessons.push({
        category: 'quality',
        lesson: 'High correction rate indicates specification gaps or unclear acceptance criteria',
        action: 'Strengthen requirements phase (P2) with concrete ACs and examples',
        priority: 'high'
      });
    } else if (p.type === 'high-defect-rate') {
      lessons.push({
        category: 'process',
        lesson: 'Elevated defect rate suggests insufficient review coverage',
        action: 'Add pre-commit quality gates and pair review assignments',
        priority: 'critical'
      });
    } else if (p.type === 'slow-cycle-time') {
      lessons.push({
        category: 'efficiency',
        lesson: 'Long cycle times indicate blocking dependencies or scope creep',
        action: 'Break tickets into smaller units; enforce ONE-SHOT sizing',
        priority: 'medium'
      });
    } else if (p.type === 'low-throughput') {
      lessons.push({
        category: 'capacity',
        lesson: 'Low completion rate suggests agent capacity mismatch or task complexity underestimation',
        action: 'Review agent skill matching and task decomposition',
        priority: 'high'
      });
    }
  });
}

if (analysis.bottlenecks) {
  analysis.bottlenecks.forEach(b => {
    if (b.type === 'agent-correction-hotspot') {
      lessons.push({
        category: 'agent-performance',
        lesson: 'Agent ' + b.agent + ' has ' + b.count + ' corrections — possible skill gap or overload',
        action: b.suggestion,
        priority: 'high'
      });
    }
  });
}

const healthScore = Math.round(analysis.healthScore || 0);
if (healthScore < 50) {
  lessons.push({
    category: 'overall',
    lesson: 'Project health score is ' + healthScore + '/100 — systemic improvements needed',
    action: 'Schedule a focused retrospective with process owners',
    priority: 'critical'
  });
} else if (healthScore < 75) {
  lessons.push({
    category: 'overall',
    lesson: 'Project health score is ' + healthScore + '/100 — targeted improvements recommended',
    action: 'Address top 2 patterns before next sprint',
    priority: 'medium'
  });
}

return [{
  json: {
    projectId: data.projectId,
    runId: data.runId,
    metrics: data.metrics,
    analysis: data.analysis,
    lessons,
    completedAt: new Date().toISOString()
  }
}];
